module top_module(clk, reset, d, q, qn);input clk, reset, d;
   output reg q, qn; // Changed to output reg for sequential logic

     wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge reset or posedge dbg_halt) begin
      if (reset == 0) begin
         q <= 0;
         qn <= 1;
      end else begin
         q <= d;
         qn <= ~d;
      end
   end
endmodule
